def parse_saml_response(saml_response):
    """Parse SAML response and extract assertion data"""
    try:
        # Decode base64 encoded response
        decoded_response = base64.b64decode(saml_response)
        
        # Parse XML
        root = ET.fromstring(decoded_response)
        
        # Find assertion
        assertion = root.find('.//saml:Assertion', namespaces=SAML_NS)
        if assertion is None:
            raise ValueError("No Assertion found in SAML response")
        
        # Extract user attributes
        attributes = {}
        attribute_statements = assertion.findall('.//saml:AttributeStatement', namespaces=SAML_NS)
        
        for attr_statement in attribute_statements:
            attributes_list = attr_statement.findall('.//saml:Attribute', namespaces=SAML_NS)
            for attr in attributes_list:
                attr_name = attr.get('Name')
                attr_values = attr.findall('.//saml:AttributeValue', namespaces=SAML_NS)
                if attr_values:
                    attributes[attr_name] = [val.text for val in attr_values]
        
        # Extract subject (user identifier)
        subject = assertion.find('.//saml:Subject', namespaces=SAML_NS)
        subject_name = None
        if subject is not None:
            name_id = subject.find('.//saml:NameID', namespaces=SAML_NS)
            if name_id is not None:
                subject_name = name_id.text
        
        # Extract conditions
        conditions = assertion.find('.//saml:Conditions', namespaces=SAML_NS)
        not_before = None
        not_on_or_after = None
        if conditions is not None:
            not_before = conditions.get('NotBefore')
            not_on_or_after = conditions.get('NotOnOrAfter')
        
        # Extract issuer
        issuer = assertion.find('.//saml:Issuer', namespaces=SAML_NS)
        issuer_name = issuer.text if issuer is not None else None
        
        return {
            'assertion': assertion,
            'subject': subject_name,
            'attributes': attributes,
            'conditions': {
                'not_before': not_before,
                'not_on_or_after': not_on_or_after
            },
            'issuer': issuer_name
        }
    except Exception as e:
        raise ValueError(f"Failed to parse SAML response: {str(e)}")

def validate_saml_assertion(assertion_data):
    """Validate SAML assertion"""
    try:
        # Check if assertion exists
        if not assertion_data.get('assertion'):
            raise ValueError("Assertion not found in response")
        
        # Validate conditions
        conditions = assertion_data.get('conditions', {})
        not_before = conditions.get('not_before')
        not_on_or_after = conditions.get('not_on_or_after')
        
        # Check timestamp validity
        if not_before:
            not_before_dt = datetime.fromisoformat(not_before.replace('Z', '+00:00'))
            if datetime.utcnow() < not_before_dt:
                raise ValueError("Assertion not yet valid")
        
        if not_on_or_after:
            not_on_or_after_dt = datetime.fromisoformat(not_on_or_after.replace('Z', '+00:00'))
            if datetime.utcnow() > not_on_or_after_dt:
                raise ValueError("Assertion expired")
        
        return True
    except Exception as e:
        raise ValueError(f"Assertion validation failed: {str(e)}")

def create_user_session(user_data):
    """Create user session from SAML attributes"""
    session['user'] = {
        'subject': user_data.get('subject'),
        'attributes': user_data.get('attributes', {}),
        'issuer': user_data.get('issuer'),
        'authenticated_at': datetime.utcnow().isoformat()
    }
    return session['user']

